// ─── Types ────────────────────────────────────────────────────────────────────

type SpreadPoint = { x: number; y: number; rot: number };

// ─── GSAP loader — module-level cache, loaded once ───────────────────────────
// Using a promise cache avoids re-importing and is safe across HMR
// because the module itself is the cache boundary.
let gsapPromise: Promise<any> | null = null;

function getGSAP(): Promise<any> {
  if (!gsapPromise) {
    gsapPromise = import("gsap").then((mod) => mod.gsap ?? mod.default);
  }
  return gsapPromise;
}

// ─── Pure helpers — outside component so they're never recreated ──────────────

function createSpreadVariant(base: readonly SpreadPoint[]): SpreadPoint[] {
  return base.map((p) => {
    const xShift = 24 + Math.random() * 34;
    const dx     = (Math.random() > 0.5 ? 1 : -1) * xShift;
    const drot   = (Math.random() - 0.5) * 8;
    return {
      x:   Math.round(p.x + dx),
      y:   Math.round(p.y),
      rot: p.rot + drot,
    };
  });
}

