function LaurelBadge({ quote, source }: { quote: string; source: string }) {
  const [displayQuote,  setDisplayQuote]  = useState(quote);
  const [displaySource, setDisplaySource] = useState(source);
  const textWrapRef  = useRef<HTMLDivElement>(null);
  const textInnerRef = useRef<HTMLDivElement>(null);
  const rightWheatRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (quote === displayQuote && source === displaySource) return;

    const inner = textInnerRef.current;
    if (!inner) {
      const rafId = requestAnimationFrame(() => {
        setDisplayQuote(quote);
        setDisplaySource(source);
      });
      return () => cancelAnimationFrame(rafId);
    }

    const fadeOut = inner.animate(
      [
        { opacity: 1, transform: "translateY(0px)" },
        { opacity: 0, transform: "translateY(-8px)" },
      ],
      { duration: 700, easing: "cubic-bezier(0.22,1,0.36,1)", fill: "forwards" },
    );

    fadeOut.onfinish = () => {
      setDisplayQuote(quote);
      setDisplaySource(source);
    };

    return () => {
      fadeOut.onfinish = null;
      fadeOut.cancel();
    };
  }, [quote, source, displayQuote, displaySource]);

  useEffect(() => {
    const right          = rightWheatRef.current;
    const previousRightX = right?.getBoundingClientRect().left ?? 0;

    const inner = textInnerRef.current;
    const wrap  = textWrapRef.current;
    if (inner && wrap) {
      const targetWidth = Math.ceil(inner.scrollWidth);
      const startWidth  = Math.max(110, targetWidth - 52);
      wrap.style.width  = `${startWidth}px`;
      wrap.animate(
        [{ width: `${startWidth}px` }, { width: `${targetWidth}px` }],
        { duration: 1400, easing: "cubic-bezier(0.22,1,0.36,1)", fill: "forwards" },
      );
    }

    textInnerRef.current?.animate(
      [
        { opacity: 0, transform: "translateY(8px)" },
        { opacity: 1, transform: "translateY(0px)" },
      ],
      { duration: 1400, easing: "cubic-bezier(0.22,1,0.36,1)", fill: "forwards" },
    );

    if (right) {
      requestAnimationFrame(() => {
        const nextRightX = right.getBoundingClientRect().left;
        const dx         = previousRightX - nextRightX;
        right.animate(
          [
            { transform: `translateX(${dx}px)` },
            { transform: "translateX(0px)" },
          ],
          { duration: 1400, easing: "cubic-bezier(0.22,1,0.36,1)", fill: "forwards" },
        );
      });
    }
  }, [displayQuote, displaySource]);

  return (
    <div className="flex items-end text-white" style={{ gap: 6 }}>
      <WheatLaurelSVG />
      <div ref={textWrapRef} className="relative overflow-hidden" style={{ width: "fit-content" }}>
        <div ref={textInnerRef} style={{ opacity: 1, textAlign: "center", width: "max-content" }}>
          <p
            className="font-extrabold leading-none"
            title={displayQuote}
            style={{
              fontSize:   "clamp(2.05rem, 3.2vw, 2.55rem)",
              fontFamily: "Georgia, serif",
              fontStyle:  "italic",
            }}
          >
            {displayQuote}
          </p>
          <p
            className="font-black uppercase"
            title={displaySource}
            style={{ fontSize: "1.02rem", lineHeight: 1.05, letterSpacing: "0.01em", marginTop: 4 }}
          >
            {displaySource}
          </p>
        </div>
      </div>
      <div ref={rightWheatRef} style={{ transform: "translateX(0)" }}>
        <WheatLaurelSVG flipped />
      </div>
    </div>
  );
}

